MyClientPlayer = class("MyClientPlayer", ClientPlayer)

function MyClientPlayer:init()
    self.teamId = ""
    self:setProperty(PlayerProperty.new())
end

function MyClientPlayer:setTeamId(id)
    self.teamId = id
    local teams = TeamManager.getTeams()
    if TeamManager.hasTeam(self.teamId) then
        --删除其他队伍队长光环，保留自己队长的光环
        for _, teamId in pairs(teams) do
            local captain = PlayerManager:getPlayerByUserId(teamId)
            if tostring(captain.userId) == self.teamId then
                captain:addCaptainEffect()
            else
                captain:removeCaptainEffect()
            end
        end
    else
        --添加所有队长的光环
        for _, teamId in pairs(teams) do
            local captain = PlayerManager:getPlayerByUserId(teamId)
            if captain then
                captain:addCaptainEffect()
            end
        end
    end
end

return MyClientPlayer